using System.Collections;
using UnityEngine;

/// <summary>
/// Mostra ou escode este NPC explicitamente (NpcController.SetVisible) — útil
/// para revelar um NPC a partir de outro evento (ex: depois de falar com o
/// Ancião, um animal escondido aparece numa clareira) ou para o esconder após
/// uma cutscene (ex: foge e desaparece).
///
/// Nota (Etapa 7): não combinar com "visibilityConditions" preenchida no mesmo
/// NPC — a avaliação automática dessas condições sobrepõe-se a esta acção no
/// frame seguinte. Usa um OU o outro mecanismo, não os dois.
/// </summary>
[System.Serializable]
public class Action_SetNpcVisible : NpcAction
{
    [Tooltip("true = mostra o NPC (sprite, colliders de trigger e movimento activos). false = esconde.")]
    public bool visible = true;

    public override IEnumerator Execute(NpcController npc)
    {
        npc.SetVisible(visible);
        yield break;
    }
}

/// <summary>
/// Muda a opacidade (alfa do SpriteRenderer) deste NPC, com transição opcional
/// ao longo de "duration" segundos (0 = aplica imediatamente). Permite fazer um
/// NPC desaparecer gradualmente (opacity = 0), ficar translúcido (ex: 0.5) ou
/// voltar a ficar totalmente opaco (1) — sem afectar colliders/movimento (para
/// esconder/mostrar "a sério", incluindo colisões, ver Action_SetNpcVisible).
/// </summary>
[System.Serializable]
public class Action_SetNpcOpacity : NpcAction
{
    [Tooltip("Opacidade final do sprite (0 = invisível, 1 = totalmente opaco).")]
    [Range(0f, 1f)] public float opacity = 1f;

    [Tooltip("Duração da transição, em segundos. 0 = aplica imediatamente (sem transição).")]
    public float duration = 0f;

    [Tooltip("Se activo, este evento espera a transição terminar antes de avançar para a ação seguinte. Se desactivado (omissão), a transição continua em segundo plano enquanto o evento prossegue (ex: diálogo continua enquanto o NPC se desfaz).")]
    public bool waitForCompletion = false;

    public override IEnumerator Execute(NpcController npc)
    {
        var routine = npc.SetOpacity(opacity, duration);
        if (waitForCompletion && routine != null)
            yield return routine;
    }
}
